//! Delivery-auth boundary for Ishikari's public content routes.

use std::sync::Arc;

use axum::{
    extract::{MatchedPath, Request, State},
    http::{StatusCode, header},
    middleware::Next,
    response::{IntoResponse, Response},
};
use mmpf_auth::{AuthFailure, DeliveryAction};

use super::AppState;

/// A verified query credential that may be copied only into URLs generated by
/// Ishikari itself. Authorization-header credentials are deliberately absent:
/// converting a header secret into a URL would be an unexpected disclosure.
#[derive(Clone)]
pub(crate) struct PropagatedAccessToken(Arc<str>);

impl PropagatedAccessToken {
    pub(crate) fn append_to(&self, url: &str) -> String {
        let separator = if url.contains('?') { '&' } else { '?' };
        let encoded = url::form_urlencoded::byte_serialize(self.0.as_bytes()).collect::<String>();
        format!("{url}{separator}access_token={encoded}")
    }
}

pub(super) async fn authorize_delivery(
    State(state): State<AppState>,
    matched: MatchedPath,
    mut request: Request,
    next: Next,
) -> Response {
    let Some(auth) = state.delivery_auth.as_ref() else {
        return next.run(request).await;
    };
    let namespace = match delivery_namespace(matched.as_str(), request.uri().path()) {
        Ok(Some(namespace)) => namespace,
        Ok(None) => return next.run(request).await,
        Err(()) => return error_response(StatusCode::BAD_REQUEST, "invalid_path"),
    };

    match auth
        .authorize(
            request.headers(),
            request.uri().query(),
            namespace.as_deref(),
            DeliveryAction::Read,
        )
        .await
    {
        Ok(authorized) => {
            tracing::debug!(
                principal_id = authorized.principal_id,
                registry_id = authorized.registry_id,
                namespace = namespace.as_deref().unwrap_or("<global>"),
                "authorized delivery request"
            );
            if let Some(token) = authorized.shared_propagated_access_token() {
                request
                    .extensions_mut()
                    .insert(PropagatedAccessToken(token));
            }
            next.run(request).await
        }
        Err(failure) => failure_response(failure),
    }
}

/// Returns `None` for non-delivery routes, `Some(None)` for a global shared
/// resource, and `Some(Some(namespace))` for namespace-scoped resources.
fn delivery_namespace(matched: &str, path: &str) -> Result<Option<Option<String>>, ()> {
    match matched {
        "/fonts/{fontstack}/{range}" => Ok(Some(None)),
        "/styles/{*style_path}" => {
            decoded_namespace(path, "/styles/").map(|namespace| Some(Some(namespace)))
        }
        route if route.starts_with("/tilesets/") => {
            decoded_namespace(path, "/tilesets/").map(|namespace| Some(Some(namespace)))
        }
        _ => Ok(None),
    }
}

/// Decode exactly as Axum's `Path` extractor will before deriving the semantic
/// leading namespace. Authorizing the raw URI segment would let `%66oo` and
/// `foo` name different grants while both handlers read the same `foo`
/// resource. An encoded slash can add style-key depth, so take the first
/// segment again after decoding.
fn decoded_namespace(path: &str, prefix: &str) -> Result<String, ()> {
    let raw = path
        .strip_prefix(prefix)
        .and_then(|rest| rest.split('/').next())
        .filter(|segment| !segment.is_empty())
        .ok_or(())?;
    let bytes = raw.as_bytes();
    let mut decoded = Vec::with_capacity(bytes.len());
    let mut index = 0;
    while index < bytes.len() {
        if bytes[index] != b'%' {
            decoded.push(bytes[index]);
            index += 1;
            continue;
        }
        let high = decode_hex(*bytes.get(index + 1).ok_or(())?).ok_or(())?;
        let low = decode_hex(*bytes.get(index + 2).ok_or(())?).ok_or(())?;
        decoded.push((high << 4) | low);
        index += 3;
    }
    let decoded = String::from_utf8(decoded).map_err(|_| ())?;
    decoded
        .split('/')
        .next()
        .filter(|namespace| !namespace.is_empty())
        .map(str::to_string)
        .ok_or(())
}

fn decode_hex(byte: u8) -> Option<u8> {
    match byte {
        b'0'..=b'9' => Some(byte - b'0'),
        b'a'..=b'f' => Some(byte - b'a' + 10),
        b'A'..=b'F' => Some(byte - b'A' + 10),
        _ => None,
    }
}

fn failure_response(failure: AuthFailure) -> Response {
    let (status, code) = match failure {
        AuthFailure::InvalidCredential => (StatusCode::UNAUTHORIZED, "invalid_token"),
        AuthFailure::Forbidden => (StatusCode::FORBIDDEN, "forbidden"),
        AuthFailure::Unavailable => (StatusCode::SERVICE_UNAVAILABLE, "auth_unavailable"),
    };
    let mut response = error_response(status, code);
    match failure {
        AuthFailure::InvalidCredential => {
            response.headers_mut().insert(
                header::WWW_AUTHENTICATE,
                axum::http::HeaderValue::from_static("Bearer"),
            );
        }
        AuthFailure::Unavailable => {
            response.headers_mut().insert(
                header::RETRY_AFTER,
                axum::http::HeaderValue::from_static("5"),
            );
        }
        AuthFailure::Forbidden => {}
    }
    response
}

fn error_response(status: StatusCode, code: &'static str) -> Response {
    (
        status,
        [
            (header::CONTENT_TYPE, "application/json"),
            (header::CACHE_CONTROL, "private, no-store"),
        ],
        format!(r#"{{"error":"{code}"}}"#),
    )
        .into_response()
}

#[cfg(test)]
mod tests {
    use super::{PropagatedAccessToken, delivery_namespace};
    use std::sync::Arc;

    #[test]
    fn scopes_only_public_delivery_routes() {
        assert_eq!(
            delivery_namespace("/styles/{*style_path}", "/styles/demo/basic/style.json").unwrap(),
            Some(Some("demo".to_string()))
        );
        assert_eq!(
            delivery_namespace(
                "/tilesets/{namespace}/{tileset_id}/{z}/{x}/{y}",
                "/tilesets/analysis/rain/1/2/3"
            )
            .unwrap(),
            Some(Some("analysis".to_string()))
        );
        assert_eq!(
            delivery_namespace("/tilesets/{tileset_id}", "/tilesets/planet").unwrap(),
            Some(Some("planet".to_string()))
        );
        assert_eq!(
            delivery_namespace("/fonts/{fontstack}/{range}", "/fonts/Noto/0-255.pbf").unwrap(),
            Some(None)
        );
        assert_eq!(delivery_namespace("/readyz", "/readyz").unwrap(), None);
    }

    #[test]
    fn namespace_authorization_uses_the_handlers_percent_decoded_identity() {
        assert_eq!(
            delivery_namespace("/styles/{*style_path}", "/styles/%66oo/basic/style.json").unwrap(),
            Some(Some("foo".to_string()))
        );
        assert_eq!(
            delivery_namespace(
                "/tilesets/{namespace}/{tileset_id}",
                "/tilesets/%66oo/terrain"
            )
            .unwrap(),
            Some(Some("foo".to_string()))
        );
        assert_eq!(
            delivery_namespace(
                "/styles/{*style_path}",
                "/styles/foo%2Fsub/basic/style.json"
            )
            .unwrap(),
            Some(Some("foo".to_string()))
        );
        assert!(
            delivery_namespace("/styles/{*style_path}", "/styles/%zz/basic/style.json").is_err()
        );
    }

    #[test]
    fn appends_an_encoded_token_without_destroying_existing_query() {
        let token = PropagatedAccessToken(Arc::from("public.a+b&c"));
        assert_eq!(
            token.append_to("https://maps.test/style.json?encoding=mlt"),
            "https://maps.test/style.json?encoding=mlt&access_token=public.a%2Bb%26c"
        );
    }
}
